#include <stdio.h>

int main(void) {
    int count;
    if (scanf("%d", &count) != 1 || count < 0 || count > 100) return 1;
    long long sum = 0;
    for (int i = 0; i < count; ++i) {
        int value;
        if (scanf("%d", &value) != 1) return 1;
        if (value == 0) continue;
        if (value < 0) break;
        sum += value;
    }
    printf("%lld\n", sum);
    return 0;
}
